import sys


def main():
    N = int(input())
    print(solve(N))


def solve(N):
    ans = 0
    for i in range(1, N+1):
        ans += len(divisors(i))
    return ans


def divisors(n):
    divisors = []
    for i in range(1, int(n**0.5)+1):
        if n % i == 0:
            divisors.append(i)
            if i != n // i:
                divisors.append(n//i)
    divisors.sort()
    return divisors


if __name__ == "__main__":
    main()
